+        // 2: Throw r1
+        Ir3Instruction::Throw { value: 1 },
+        // 3: EndTry (never reached)
+        Ir3Instruction::EndTry,
+        // 4: EnterFinally (exception pending → mode = Exception)
+        Ir3Instruction::EnterFinally,
+        // 5: LoadInt 99 (finally body still executes)
